"""
mkt-christ layer — 1 Timothy chapters 1–5 (fills all missing verses)
Output: data/commentary/mkt-christ/1timothy.json
Run: python3 scripts/zc-christ-1timothy-1-5-full.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "1": {
    "1": "<p>Paul's apostleship is 'by the command of God our Savior and of Christ Jesus our hope' — the authority behind the entire letter is Christological. The dual title 'God our Savior / Christ Jesus our hope' places Father and Son as co-sources of the apostolic mandate. Christ as 'our hope' (<em>tēs elpidos hēmōn</em>) concentrates the entire eschatological expectation in his person: not a doctrine of hope but a person who is hope — the risen, returning Lord in whom the future is secured.</p>",
    "2": "<p>Timothy as 'my true son in the faith' (<em>gnēsiō teknō en pistei</em>) — the faith that binds Paul and Timothy as father and son is faith in Christ. The fatherhood is spiritual, mediated through the gospel and the Christ who is its content. The triad 'grace, mercy, and peace from God the Father and Christ Jesus our Lord' places Christ as co-giver of the divine blessings: grace is the undeserved favor enacted at the cross; mercy is the ongoing compassion that follows from it; peace is the reconciliation between God and humanity accomplished by Christ.</p>",
    "3": "<p>The instruction to remain in Ephesus to combat false teaching is Christologically motivated — the false teachers are corrupting 'the stewardship (<em>oikonomia</em>) of God that is by faith.' The management of God's household is the administration of the gospel of Christ; the false teachers' speculative genealogies undermine the Christ-centered simplicity of that gospel. Timothy's pastoral mandate is fundamentally a Christological one: to guard the proclamation of Christ against distorting substitutes.</p>",
    "4": "<p>Myths and genealogies 'promote speculations rather than the stewardship of God that is by faith' — the counter to speculative theological elaboration is the Christ-centered oikonomia. The household of God (3:15) is organized around the gospel; the administrator of that household (Timothy) manages it by maintaining the Christological center of its proclamation. The false teaching's fundamental error is Christological displacement: something other than Christ becomes the organizing center of religious inquiry.</p>",
    "5": "<p>'The goal of this instruction is love from a pure heart, good conscience, and sincere faith' — the triad describes the Christological character formation that sound teaching produces. Love is the identifying mark of the disciples (John 13:35); the pure heart is what the beatitudes promise to those who see God (Matt 5:8); the sincere faith is the trusting relationship with Christ. The goal of Christian instruction is not doctrinal expertise but Christomorphic character — being shaped by Christ's own love, purity, and faithfulness.</p>",
    "6": "<p>Departure from love, good conscience, and sincere faith into 'meaningless talk' — the Christological failure behind vain theological dispute is a loss of the personal: when Christ is no longer the center of devotion and inquiry, the center is filled by speculation. The false teachers have drifted from a person (Christ) to a system of ideas. Christological reality is relational before it is propositional; the departure Paul diagnoses is first a departure from relationship.</p>",
    "7": "<p>'Wanting to be teachers of the law without understanding what they say or what they affirm' — the false teachers seek the authority of Torah-interpretation without recognizing that Christ is the telos of the law (Rom 10:4). The law rightly used reveals sin and drives to Christ (Gal 3:24); misused, it becomes an autonomous system of merit or speculation. The teachers of the law who do not understand the law's Christological function are the NT counterpart of Jesus's opponents in the Gospels.</p>",
    "8": "<p>'The law is good if one uses it properly' — the Christological key to proper law-use is Paul's own argument in Romans: the law diagnoses sin, but Christ is the remedy (Rom 3:20-22; 7:12-25; 8:1-4). The law properly used serves the gospel: it exposes what Christ came to cure. The false teachers use the law improperly — not as a diagnostic leading to Christ but as a constructive religious system that replaces him.</p>",
    "9": "<p>The law is made 'not for the righteous but for lawbreakers' — in Christ, the believer has been declared righteous (Rom 5:1; 8:1); the law's condemning function no longer applies to those who are in Christ Jesus (Rom 8:1: there is therefore now no condemnation). The vice list exposes the unredeemed condition that Christ came to address. The law's portrait of sin is simultaneously the portrait of what Christ saves from — the scope of his salvation matches the scope of the transgression the law identifies.</p>",
    "10": "<p>The vice list culminates with 'whatever else is contrary to sound doctrine' — sound doctrine is literally 'healthy teaching' (<em>didaskaliai hygianousēs</em>), a medical metaphor: the gospel is the medicine that heals the disease of sin catalogued in vv. 9-10. Christ as the physician who heals sin's disease is the underlying Christological metaphor (Luke 5:31-32: the well have no need of a physician; I came not to call the righteous but sinners to repentance).</p>",
    "11": "<p>'The gospel of the glory of the blessed God, which he entrusted to me' — the gospel is the gospel of God's <em>glory</em>: it reveals what God is truly like. Christ is the one in whose face the knowledge of the glory of God shines (2 Cor 4:6); the gospel that Paul proclaims is the proclamation of this Christ-glory. The entrustment (<em>episteutheēn</em>) to Paul is a commission of stewardship: he manages the Christ-glory proclamation on God's behalf.</p>",
    "12": "<p>'I thank Christ Jesus our Lord, who gave me strength' — the thanksgiving is to Christ personally, not abstractly to God. Christ is the direct agent of Paul's empowerment (<em>endunamōsanti</em>) — the same verb as Eph 6:10 (be strong in the Lord and in the strength of his might) and Phil 4:13 (I can do all things through him who strengthens me). Paul's entire apostolic capacity is Christological: he works because Christ works in him.</p>",
    "13": "<p>'I was shown mercy because I acted ignorantly in unbelief' — Christ's mercy toward the persecutor Paul is the paradigmatic demonstration of the gospel's power. The one who called the church a blasphemy (by persecuting it) is transformed into its foremost apostle. The Christological significance: Christ's mercy is not limited by the severity of the offense but extends to the worst imaginable case — the violent opponent of Christ himself. This is the mercy that defines the gospel.</p>",
    "14": "<p>'The grace of our Lord overflowed for me with the faith and love that are in Christ Jesus' — grace, faith, and love are all 'in Christ Jesus': they exist within the sphere of union with him. The grammar is significant: not faith and love directed toward Christ (though that is true) but faith and love that are located in him, participating in what he is. Christ's own faithfulness (<em>pistis Christou</em>) and his own love become the believer's through incorporation into him.</p>",
    "16": "<p>'That in me, the foremost sinner, Christ Jesus might display his perfect patience as an example to those who were to believe in him for eternal life' — Paul is the <em>hypotypōsis</em> (pattern, prototype) of Christ's patience. The display is Christocentric: Christ's patience (<em>makrothymia</em>) is what is displayed, not Paul's virtue. Christ's willingness to pursue, call, and transform the most violent opponent of the church demonstrates the limitless extension of his saving patience. Every subsequent conversion is implicit in Paul's — if Christ was patient enough for the chief of sinners, he is patient enough for any.</p>",
    "17": "<p>The doxology — 'to the King of the ages, immortal, invisible, the only God, be honor and glory for ever and ever' — is addressed to the God who is the source of the grace Paul has just narrated. The Christological movement: the doxology to God the Father rises from the Christological narrative of vv. 12-16. God is praised for what he has done in Christ; the doxology is the response to the gospel, not an abstract theistic affirmation.</p>",
    "18": "<p>'According to the prophecies previously made about you, that by them you may wage the good warfare' — Timothy's ministry is Christological warfare: the 'good warfare' (<em>tēn kalēn strateian</em>) is the apostolic mission of proclaiming Christ against the opposition of false teaching and the powers behind it (Eph 6:10-18). The prophetic commissionings that equipped Timothy for ministry are the Spirit's preparation for Christological service; the warfare is the cosmic conflict between the gospel and its opponents.</p>",
    "19": "<p>'Holding faith and a good conscience' — faith in Christ and the moral consciousness that corresponds to that faith go together; abandoning conscience ruptures the faith. The nautical metaphor of shipwreck — the most catastrophic possible failure — underlines the seriousness of moral-spiritual integrity. The faith that is shipwrecked is specifically faith in Christ; the conscience that is abandoned is the internal witness to Christ's moral standard in the believer's life.</p>",
    "20": "<p>'Handed over to Satan that they may learn not to blaspheme' — the disciplinary handing-over has a corrective goal: the blasphemer may learn not to blaspheme. Even in judgment, the Christological mercy operates: the purpose is not destruction but the recovery of those who have spoken against Christ's gospel. The formula mirrors 1 Cor 5:5 where the same discipline aims at the salvation of the spirit 'in the day of the Lord Jesus' — even the most severe church discipline is eschatologically oriented toward Christ's final judgment as the criterion.</p>"
  },
  "2": {
    "1": "<p>'Petitions, prayers, intercessions, and thanksgivings be made for all people' — the comprehensiveness of Christian prayer reflects the comprehensiveness of Christ's saving purpose: he gave himself as a ransom 'for all' (v. 6). The prayer for all people is grounded in Christ's universal saving intent; to pray for all is to align with Christ's own intercession (Heb 7:25: he always lives to make intercession for them; Rom 8:34: Christ Jesus is the one who intercedes for us).</p>",
    "2": "<p>'For kings and all those in authority' — praying for the Roman emperor is an act of participation in Christ's Lordship over all earthly authority. Christ is the King of kings (6:15; Rev 19:16); earthly rulers derive their authority from his ultimate sovereignty (John 19:11: you would have no authority over me at all unless it had been given you from above). Prayer for rulers acknowledges Christ's over-rule while seeking the conditions under which the gospel can be proclaimed without hindrance.</p>",
    "3": "<p>'This is good and pleasing to God our Savior' — the identification of God as Savior establishes the theological ground of universal prayer: the God who saves wills the salvation of all (v. 4). The Savior-God's own intent is the justification for the scope of intercession. Christ as the one through whom God's Savior-identity is enacted gives the prayer its Christological content: to pray for all is to pray that God's Christ-mediated salvation reach those prayed for.</p>",
    "4": "<p>'Who wants all people to be saved and to come to a knowledge of the truth' — the 'knowledge of the truth' (<em>epignōsis alētheias</em>) is knowledge of Christ, who is the truth (John 14:6). The salvific will is simultaneously a Christological will: God wills that all come to know Christ. The phrase 'knowledge of truth' becomes a Pastoral Epistles shorthand for the gospel content (1 Tim 4:3; 2 Tim 2:25; 3:7; Tit 1:1) — the revealed Christological reality that saves those who receive it.</p>",
    "6": "<p>'Who gave himself as a ransom for all, the testimony given at its proper time' — the ransom-giving (<em>antilytron hyper pantōn</em>) is the definitive Christological act of the letter. <em>Antilytron</em> (found only here in the NT) is the substitutionary ransom paid in the place of another. Christ's self-giving was not exemplary only but substitutionary: he stood in the place of those who owed the debt they could not pay. The 'proper time' (<em>kairois idiois</em>) frames the cross as the divinely appointed moment of Christological fulfillment.</p>",
    "7": "<p>'For this I was appointed a herald and apostle — I am telling the truth, I am not lying — a teacher of the Gentiles in faith and truth' — Paul's apostolic commission is entirely in service of making the universal ransom (v. 6) known to the Gentile world. The chain of logic: Christ gave himself for all (v. 6) → Paul is appointed to announce this to the Gentiles (v. 7) → therefore pray for all (v. 1). The apostle's mandate is the announcement of Christological universalism; his oath-formula underlines the seriousness of that commission.</p>",
    "8": "<p>'Men everywhere to pray, lifting up holy hands without anger or disputing' — prayer offered 'without anger or disputing' reflects the peace that Christ accomplished (Eph 2:14-16: he himself is our peace... reconciling both parties to God in one body through the cross). The community that is at peace with God through Christ should demonstrate that peace in its internal life; anger and disputing in the assembly contradict the reconciliation that the prayer it offers celebrates.</p>",
    "9": "<p>'Women to dress modestly with decency and propriety, not with braided hair or gold or pearls or costly clothing' — the instruction redirects the social energy of status display. In Christ there is neither Jew nor Greek, slave nor free, male nor female (Gal 3:28); the assembly where Christ is confessed is a community in which social hierarchies expressed through dress are relativized. The modest dress is a visible Christological statement: the adornment that matters is conformity to Christ, not social rank.</p>",
    "10": "<p>'But with good deeds, as is appropriate for women who profess godliness' — good deeds are the Christological alternative to status display. The women who supported Jesus's ministry (Luke 8:1-3) and the patron-women of Paul's churches (Phoebe, Lydia) embodied this: visible, active service as the mode of identity in the Christ-community. The profession of godliness (<em>eusebeia</em>) is verified by the deeds that accompany it — a Christological pattern where faith produces fruit.</p>",
    "11": "<p>'A woman should learn in quietness and full submission' — the instruction presupposes an earlier radical step: women should <em>learn</em>. In the community of Christ, women's access to formal instruction is assumed (Gal 3:28: all are one in Christ Jesus); the qualification of manner (quietness, submission) governs the mode, not the fact, of women's learning. The Christ-community's commitment to teaching all its members is itself a Christological extension of the rabbi who called men and women disciples.</p>",
    "12": "<p>'I do not permit a woman to teach or to exercise authority over a man' — the instruction is placed in the context of the false teaching threatening Ephesus (2 Tim 3:6-7 indicates women were being targeted by false teachers). Whether this is a universal Christological principle or a contextual correction, the Christological criterion is the same: leadership in the community of Christ is servant-leadership modeled on Christ's own servant pattern (Mark 10:42-45), not self-assertion or the exercise of unauthorized influence.</p>",
    "13": "<p>'For Adam was formed first, then Eve' — the appeal to the creation order grounds the instruction in the protological rather than the cultural. Christ as the second Adam (Rom 5:14; 1 Cor 15:45) does not abolish the created order but redeems it; the new creation in Christ restores rather than eliminates the creational structures. The Christological reading of Genesis 2 operates within a typological framework where creation-order anticipates the Christ-pattern of headship and helpership in the new covenant community.</p>",
    "14": "<p>'And Adam was not deceived, but the woman was deceived and became a transgressor' — the Genesis 3 narrative is read Christologically as a pattern that the false teaching in Ephesus reprises. If women in the Ephesian community were the primary conduit of false teaching (2 Tim 3:6-7), Paul's use of the Eve-deception pattern is a contextual warning: the susceptibility to deception that Genesis 3 narrates is being repeated. Christ as the truth (John 14:6) is the antidote to deception; guarding access to his truth-claims is the pastoral concern.</p>",
    "15": "<p>'But women will be saved through the childbearing, if they continue in faith and love and holiness with self-control' — if 'the childbearing' (<em>tēs teknogonias</em>) refers to the Incarnation — the birth of the Christ — then the verse carries Christological weight: it is through the birth of the Messiah that the deception in Eden is reversed (Gen 3:15: I will put enmity between you and the woman; her seed will bruise your head). The woman's salvation comes through the fruit of the woman's womb — the one born of Mary who is the seed of the woman. The ongoing condition (faith, love, holiness, self-control) describes the Christological character formation that marks those who are saved through him.</p>"
  },
  "3": {
    "1": "<p>'If anyone aspires to oversee, he desires a good work' — the overseer's role is defined as <em>work</em> (<em>ergou</em>): service, not honor. This reflects the servant-Christology of the Pastoral Epistles: leadership in Christ's community is defined by the pattern of the one who came not to be served but to serve (Mark 10:45). Aspiring to serve — genuinely to shoulder the burden of others' spiritual welfare — is a good desire because Christ himself defined leadership as self-giving service.</p>",
    "2": "<p>'An overseer must be above reproach, faithful to his wife, temperate, self-controlled, respectable, hospitable, able to teach' — the character portrait of the overseer is implicitly Christomorphic: the qualities listed are Christ's own character reproduced in the leader. Faithful to his wife mirrors Christ's covenant faithfulness to the church as his bride (Eph 5:25-27); self-controlled and respectable mirror the dignity of the one who never sinned; hospitable mirrors the one who welcomes the excluded (Luke 15); able to teach mirrors the Teacher himself.</p>",
    "3": "<p>'Not given to drunkenness, not violent but gentle, not quarrelsome, not a lover of money' — the negative qualifications describe what Christ was not: not addicted to anything, not prone to force or anger, not contentious, not acquisitive. The gentle (<em>epieikēs</em>) overseer mirrors the gentleness of Christ (Matt 11:29: I am meek and humble of heart; 2 Cor 10:1: by the meekness and gentleness of Christ). The character list is shaped by the Christological pattern; the overseer is to be Christ-like in precisely these respects.</p>",
    "4": "<p>'He must manage his own household well, seeing that his children are submissive with all dignity' — the household as the training ground for community leadership reflects the Christological principle that faithfulness in small things qualifies for larger responsibility (Luke 16:10; 19:17: because you have been faithful in a very little, you shall have authority over ten cities). The oversight of the church is a larger-scale version of the oversight of the household; Christ's own kingdom-oversight is the model that both shadow.</p>",
    "5": "<p>'If someone does not know how to manage his own household, how will he care for God's church?' — the God's church (<em>ekklēsia theou</em>) is the assembly that belongs to God by virtue of Christ's redemption (Acts 20:28: the church of God which he obtained with his own blood). The pastor's stewardship is of a community purchased by the blood of Christ; this frames pastoral care with an enormous gravity. Failure to care for the Christ-purchased community is a failure toward the one whose blood secured it.</p>",
    "6": "<p>'Not a recent convert, lest he become puffed up with conceit and fall into the devil's judgment' — the devil's judgment was pride before a fall; Satan's downfall began with the aspiration to be like God (Isa 14:13-14; cf. 1 Tim 3:6). Christ's own humility — who being in the form of God did not count equality with God a thing to be grasped but emptied himself (Phil 2:6-7) — is the counter-pattern to the devil's pride. The newly planted convert who has not yet been formed by Christ's humility is vulnerable to the satanic pattern.</p>",
    "7": "<p>'He must have a good reputation with outsiders, lest he fall into disgrace and the devil's snare' — the church's external witness depends on the character of its leaders. Christ himself was questioned about his associations and reputation (Matt 11:19: he is a friend of tax collectors and sinners); yet his character remained above reproach. The overseer's good reputation with outsiders extends Christ's witness into the community through the visible character of those who lead in his name.</p>",
    "8": "<p>'Deacons likewise must be dignified, not double-tongued, not addicted to much wine, not greedy for dishonest gain' — the deacon's qualifications mirror Christ's own integrity: not double-tongued (Christ whose yes is yes and no is no, Matt 5:37), not addicted (Christ who was master of himself), not greedy (Christ who though rich became poor for our sake, 2 Cor 8:9). The servant-office of the deacon models itself on Christ the servant (<em>diakonos</em>) who came to serve rather than to be served.</p>",
    "9": "<p>'They must hold the mystery of the faith with a clear conscience' — the mystery of the faith is the revealed Christ-event (the mystery of godliness, v. 16: Christ manifested in flesh). Holding this mystery 'with a clear conscience' means the deacon's life matches the mystery he holds: the gospel of Christ's self-giving service is authenticated by the deacon's own self-giving service. Doctrinal fidelity without moral integrity is a contradiction — the Christ who is proclaimed must be embodied in the proclaimer.</p>",
    "10": "<p>'Let them also be tested first; and if found blameless, let them serve as deacons' — the testing process mirrors the Christological pattern of proved faithfulness before appointment. Christ himself was tested — in the wilderness (Matt 4:1-11), in the garden (Luke 22:42-44), on the cross — before being vindicated and exalted (Phil 2:9). The deacon's testing is a reflection of the same principle: faithfulness under scrutiny qualifies for public service.</p>",
    "11": "<p>'Women likewise must be dignified, not slanderers, but temperate, faithful in all things' — whether these are female deacons or deacons' wives, the Christological pattern applies equally: dignity, truthfulness, temperance, and faithfulness are the character of Christ reproduced. The qualifier 'faithful in all things' (<em>en pasin</em>) is absolute: total fidelity in all domains of conduct, mirroring the one who was faithful over God's house (Heb 3:6: Christ was faithful over God's house as a son).</p>",
    "12": "<p>'Let deacons each be the husband of one wife, managing their children and their own households well' — the household-management standard for deacons is identical to the overseer's: the domestic sphere is the formation ground for Christological leadership. The single-minded marital faithfulness ('husband of one wife') mirrors Christ's faithfulness to the one church, his bride. The household managed well is the visible sign of the character that qualifies for larger service in Christ's community.</p>",
    "13": "<p>'Those who serve well as deacons gain a good standing for themselves and also great confidence in the faith that is in Christ Jesus' — the confidence (<em>parrēsia</em>) in the faith that is in Christ Jesus is the boldness of access to God that comes through union with Christ (Eph 3:12: in him we have boldness and access with confidence through our faith in him). Faithful diaconal service deepens the servant's own Christological confidence — serving others in Christ's name strengthens one's own standing before Christ.</p>",
    "14": "<p>'I hope to come to you soon, but I am writing these things in case I delay' — the letter functions as a present form of apostolic presence. Paul mediates Christ's authority through writing just as through personal presence; the written word carries the same Christological weight. Christ himself commissioned apostolic teaching as the mode of his continued presence (Matt 28:20: teaching them to observe all that I have commanded you; and I am with you always). The letter is a form of that continued Christological presence.</p>",
    "15": "<p>'The household of God, which is the church of the living God, the pillar and buttress of truth' — the church as God's household is organized around Christ as the head of the household (Eph 1:22-23; Col 1:18). The church upholds truth because Christ is the truth (John 14:6); the church is the 'pillar and buttress' of truth because it is the body of the one who is truth. The church's identity as truth-bearer is entirely Christological: it upholds what Christ is.</p>"
  },
  "4": {
    "1": "<p>'The Spirit expressly says that in later times some will depart from the faith, devoting themselves to deceitful spirits and teachings of demons' — the departure 'from the faith' is departure from faith in Christ; the deceitful spirits' teachings are Christologically distorting. The Spirit who speaks this warning is the Spirit of Christ (1 Pet 1:11), and the warning serves the protection of the Christ-confession. The 'later times' that the Spirit announces are the present age inaugurated by Christ's first coming and extending to his parousia.</p>",
    "2": "<p>'Through the insincerity of liars whose consciences are seared' — the cauterized conscience has lost responsiveness to the Christ who stands at the door and knocks (Rev 3:20). Christ as the truth (John 14:6) generates conscience in those who are being conformed to him; to sear the conscience is to suppress the Christ-truth that would otherwise produce moral discomfort. The false teachers' insincerity is Christological failure at the level of personal integrity.</p>",
    "3": "<p>'Who forbid marriage and require abstinence from foods that God created to be received with thanksgiving by those who believe and know the truth' — the false teaching that rejects God's creation is a rejection of the Creator's goodness attested by Christ's own enjoyment of creation: he ate with sinners, turned water into wine, fed thousands with bread and fish. Christ's incarnation is the definitive theological statement that matter is good; rejecting food and marriage contradicts the Incarnation's witness to the goodness of creaturely existence.</p>",
    "4": "<p>'For everything created by God is good, and nothing is to be rejected if it is received with thanksgiving' — the creation-goodness principle is the theological ground of the Incarnation: the God who declares all created things good is the God who takes on created flesh in Christ. Christ's embodied ministry — eating, drinking, sleeping, weeping, laughing — is the fullest possible endorsement of creation's goodness. The false teachers' rejection of creation implicitly rejects the Incarnation's vindication of the material order.</p>",
    "5": "<p>'It is sanctified by the word of God and prayer' — the word of God that sanctifies food is the word that, in Christ, became flesh (John 1:14). The sanctification of ordinary food by thanksgiving-prayer is a Christological act: the believer who gives thanks does so through Christ (Col 3:17: whatever you do in word or deed, do everything in the name of the Lord Jesus, giving thanks to God the Father through him). Every meal is Christologically consecrated in this sense.</p>",
    "6": "<p>'If you put these things before the brothers, you will be a good servant (<em>diakonos</em>) of Christ Jesus, nourished on the words of the faith and of the good doctrine you have followed' — Timothy's servanthood is explicitly 'of Christ Jesus': he is Christ's minister, Christ's representative. The nourishment on 'words of the faith' is the Christological feeding that sustains him: immersion in the Christ-centered proclamation is the minister's own spiritual sustenance, just as Christ is the bread of life (John 6:35).</p>",
    "7": "<p>'Have nothing to do with irreverent, silly myths; train yourself for godliness' — godliness (<em>eusebeia</em>) in the Pastoral Epistles is the Christological orientation of the whole person toward God; it is defined by the 'mystery of godliness' hymn (3:16) where Christ himself is the content and embodiment of godliness. To train for godliness is to be formed by the pattern of the one in whom godliness is incarnated.</p>",
    "8": "<p>'Bodily training is of some value, but godliness is valuable in every way, as it holds promise for the present life and also for the life to come' — the eschatological benefit of godliness reaches beyond death because it is participation in the life of the one who conquered death (John 11:25-26: I am the resurrection and the life; whoever lives and believes in me shall never die). The present-and-future promise of godliness reflects the already-and-not-yet structure of Christ's kingdom: the resurrection life is already present in the Spirit, not-yet fully consummated at his parousia.</p>",
    "9": "<p>'The saying is trustworthy and deserving of full acceptance' — the faithful saying formula introduces or endorses a formulation of the Christological gospel that the community holds and transmits. The 'trustworthy' (<em>pistos</em>) content is trustworthy because Christ himself is faithful (<em>pistos</em>, 2 Tim 2:13; Rev 1:5; 19:11); the formula's reliability is anchored in the reliability of the person the content proclaims.</p>",
    "10": "<p>'We labor and strive because we have set our hope on the living God, who is the Savior of all people, especially of those who believe' — the 'living God' who is Savior is the God who raised Christ from the dead (Rom 4:24; 1 Pet 1:21). The hope that sustains apostolic labor is resurrection hope; the Savior in whom that hope is placed is the God who has already demonstrated his saving power in the resurrection of Christ. The 'especially of those who believe' distinguishes the scope of God's salvific intent (all people) from the realization of salvation (those who believe).</p>",
    "11": "<p>'Command and teach these things' — the dual authority of apostolic command and reasoned teaching reflects Christ's own teaching authority: he taught as one who had authority (Matt 7:29). Timothy's mandate to command and teach is derivative from Christ's authority; he speaks in Christ's name (1 Cor 5:4; Col 3:17: whatever you do in word or deed, do everything in the name of the Lord Jesus). The content commanded and taught is Christological: the faithful sayings, the mystery of godliness, the sound doctrine that derives from Christ.</p>",
    "12": "<p>'Let no one despise you for your youth, but set the believers an example in speech, in conduct, in love, in faith, in purity' — the six-fold example Timothy is to model is the Christological character he is to embody and reproduce. Speech, conduct, love, faith, and purity describe Christ himself: his word was truth (John 14:6), his conduct was sinless (Heb 4:15), his love was self-giving (John 15:13), his faith was unwavering, his purity absolute. Timothy's example functions as a local embodiment of the Christ-pattern in the Ephesian community.</p>",
    "13": "<p>'Devote yourself to the public reading of Scripture, to exhortation, to teaching' — the reading of Scripture in the assembly is reading the texts that witness to Christ (John 5:39: these are they that testify about me; Luke 24:27: beginning with Moses and all the Prophets, he interpreted to them in all the Scriptures the things concerning himself). The exhortation and teaching that follow are Christological interpretation: making the Christ-witness of the Scriptures available to the community.</p>",
    "14": "<p>'Do not neglect the gift that is in you, which was given you by prophecy when the council of elders laid their hands on you' — the charismatic gift Timothy received is a Christological endowment: spiritual gifts are the Spirit of Christ at work in the community (1 Cor 12:4-6: there are varieties of gifts but the same Spirit, same Lord, same God). The ordination rite is a Christological commissioning: the one who received the gift serves Christ through it.</p>",
    "15": "<p>'Practice these things; immerse yourself in them, so that everyone may see your progress' — the progress (<em>prokopē</em>) that others observe is progress in Christological formation: conformity to the image of Christ that the Spirit produces (2 Cor 3:18: we are being transformed into the same image from one degree of glory to another). Timothy's visible progress is the community's evidence that the gospel of Christ produces the character it promises.</p>",
    "16": "<p>'Keep a close watch on yourself and on the teaching. Persist in this, for by so doing you will save both yourself and your hearers' — the salvation of Timothy and his hearers is mediated through the faithful ministry of the word. The word proclaimed is the word of Christ (Col 3:16); the salvation it produces is Christ-salvation. Timothy's pastoral perseverance is in service of a Christ-centered salvific process: his continuing faithfulness extends the reach of Christ's saving power to those who hear.</p>"
  },
  "5": {
    "1": "<p>'Do not rebuke an older man harshly, but exhort him as a father' — the family metaphor for the church (brothers, sisters, fathers, mothers) reflects the new kinship created by Christ. In Christ, believers are brothers and sisters of the same heavenly Father (Matt 12:49-50: whoever does the will of my Father in heaven is my brother and sister and mother); the kinship categories that structure Paul's pastoral instructions are Christologically generated. Treating older men as fathers extends the honor-code of creation into the new family Christ creates.</p>",
    "2": "<p>'Older women as mothers, younger women as sisters with absolute purity' — the purity required in the pastoral relationship with younger women reflects the holiness of the Christ-community. The church is the bride of Christ, presented to him as a pure virgin (2 Cor 11:2; Eph 5:27: without spot or wrinkle or any such thing, holy and blameless). The absolute purity Timothy is to maintain in relating to younger women is the pastoral form of protecting the holiness that belongs to Christ's bride.</p>",
    "3": "<p>'Honor widows who are truly widows' — the church's care for the genuinely destitute widow is a specific expression of Christ's own concern for those the world neglects. Christ himself commended the widow's offering (Mark 12:41-44), restored the widow of Nain's son (Luke 7:11-17), and spoke against those who 'devour widows' houses' (Mark 12:40). The community of Christ inherits his pastoral concern for the widow as one of the most vulnerable members of the community.</p>",
    "4": "<p>'If a widow has children or grandchildren, let them first learn to show godliness to their own household and to make some return to their parents' — godliness (<em>eusebeia</em>) expressed in family care is a Christological virtue: Christ himself, even from the cross, cared for his mother (John 19:26-27: when Jesus saw his mother... he said to the disciple, behold your mother). The Christological pattern of personal care for family members in need is the model for the family provision that Paul mandates.</p>",
    "5": "<p>'The widow who is truly alone has set her hope on God and continues in supplications and prayers night and day' — the widow who hopes in God is hoping in the God who raised Christ from the dead; her hope is Christologically shaped. The practice of 'supplications and prayers night and day' mirrors the intercession of Christ himself who, as the exalted high priest, ever lives to make intercession (Heb 7:25). The praying widow participates in the Christological intercession that sustains the community.</p>",
    "6": "<p>'The widow who is self-indulgent is dead even while she lives' — the death-in-life of the self-indulgent widow is the opposite of the new life in Christ. Paul's language elsewhere describes those without Christ as 'dead in trespasses and sins' (Eph 2:1); to live for pleasure rather than for Christ is to remain in the death-condition from which Christ raises the believer. Life is participation in Christ (Phil 1:21: for me to live is Christ and to die is gain); to live for self rather than Christ is to choose a kind of death.</p>",
    "7": "<p>'Command these things as well, so that they may be without reproach' — the church's care for widows is a command, not an option, because it flows from Christ's own command to love (John 13:34-35) and his pattern of caring for the vulnerable. The 'without reproach' (<em>anepilēptoi</em>) standard applies equally to the community's social witness: a church that neglects its widows is not living consistently with the Christ who proclaimed good news to the poor (Luke 4:18).</p>",
    "8": "<p>'If anyone does not provide for his own, and especially for members of his household, he has denied the faith and is worse than an unbeliever' — to deny the faith in practice (by abandoning family members) is to deny Christ in practice. The faith confessed is faith in the Christ who said you will be judged by how you treated the least of these (Matt 25:40); failing the least in one's own household is failing Christ in his most immediate claim on one's care.</p>",
    "9": "<p>'Let a widow be enrolled if she is not less than sixty years of age, having been the wife of one husband' — the formal enrollment of widows is a Christological institution: it recognizes those who have given their lives to the service of the community formed by Christ, and it extends the community's care to them in return. The single-minded marital faithfulness ('wife of one husband') mirrors the covenant faithfulness that characterizes the Christ-community's relationships.</p>",
    "10": "<p>'Having a reputation for good works: if she has brought up children, shown hospitality, washed the saints' feet, cared for the afflicted, devoted herself to every good work' — the enrolled widow's qualification is a track record of exactly the practical service that Christ modeled: feet-washing (John 13), showing hospitality (he was always accepting invitations and extending welcome), caring for the afflicted (his healing ministry). The enrolled widow's life is a sustained embodiment of the Christ-pattern in domestic and communal service.</p>",
    "11": "<p>'Younger widows, refuse to enroll, for when they grow wanton against Christ, they want to marry' — 'to grow wanton against Christ' (<em>katastreniasosin tou Christou</em>) is remarkable language: the younger widow who pursues pleasure is described as acting against Christ personally — as if the Christ-relationship is a marital covenant that the pursuit of pleasure violates. The Pauline metaphor of the church as Christ's bride (2 Cor 11:2; Eph 5:25-27) underlies the language: abandoning the devoted widow-service is a form of infidelity to Christ.</p>",
    "12": "<p>'They incur condemnation for having abandoned their former faith' — the 'former faith' (<em>prōtēn pistin</em>) that is abandoned is their faith in Christ, around which the pledge was organized. To abandon the dedicated widow-service is to abandon the Christological center of that service. The condemnation (<em>krima</em>) is not eternal damnation but the pastoral judgment that their conduct contradicts their confession — a Christological inconsistency.</p>",
    "13": "<p>'Besides that, they learn to be idlers, going about from house to house, and not only idlers but also gossips and busybodies, saying what they should not' — the idleness and gossip describe the trajectory of those who have departed from Christological purpose. Christ came to do the will of the one who sent him (John 4:34: my food is to do the will of him who sent me); the purposeful activity that flows from that center is the opposite of aimless wandering and idle talk. Departure from Christ-centered purpose produces the aimlessness that the false teachers embody.</p>",
    "14": "<p>'I would have younger widows marry, bear children, manage their households, give the adversary no occasion for slander' — the 'adversary' (<em>antikeimenos</em>) whose occasion for slander is to be avoided is either the human opponents of the community or the devil (as in 3:7: the devil's snare; 3:6: the devil's condemnation). The practical wisdom of directing younger widows toward household management serves the Christological purpose of guarding the community's witness: the devil works through scandal and slander, and practical Christian living forecloses his opportunities.</p>",
    "15": "<p>'For some have already strayed to follow Satan' — the trajectory away from Christ leads inevitably toward Satan: there is no neutral territory. The Christological choice is binary: the shepherd or the adversary (John 10:10-12: the thief comes to steal and kill; the good shepherd gives his life). Those who have followed Satan have rejected the one who is life in favor of the one who brings destruction; the pastoral warning is to prevent others from following the same path.</p>",
    "16": "<p>'If any believing woman has relatives who are widows, let her care for them. Let the church not be burdened, so that it may care for those who are truly widows' — the distribution of care between family, patron-believers, and the church reflects the Christological community's economic wisdom. The body of Christ has limited resources; the stewardship of those resources — including whom the church formally supports — is a Christological responsibility. Misallocating care would leave 'true widows' unserved: those whom Christ specially designated as the community's responsibility.</p>",
    "17": "<p>'Let the elders who rule well be considered worthy of double honor, especially those who labor in preaching and teaching' — the double honor for teaching elders reflects the Christological weight of the teaching ministry: those who labor in the word proclaim Christ (Col 1:28: we proclaim him, warning everyone and teaching everyone with all wisdom). The labor of preaching is the labor of making Christ known; those who bear this burden deserve proportional material and social recognition.</p>",
    "18": "<p>'The Scripture says, you shall not muzzle an ox when it treads out the grain, and the laborer deserves his wages' — Christ himself taught that the laborer deserves his wages (Luke 10:7), and Paul here places that teaching alongside Deuteronomy as dual warrant. The co-authority of Christ's teaching and Torah is the Christological ground of the financial support Paul argues for: the gospel that Paul and Timothy proclaim is worth supporting financially because it is Christ's own commissioned proclamation.</p>",
    "19": "<p>'Do not admit a charge against an elder except on the evidence of two or three witnesses' — the Deuteronomic witness-rule (Deut 19:15) is applied by Christ to community discipline in Matt 18:16 and here to elder-accusation. The Christological continuity: the same Lord who gave the Torah gives the gospel-community its governance principles; Jesus's application of the Deuteronomic witness rule to the church (Matt 18:16) provides the hermeneutical bridge Paul draws on.</p>",
    "20": "<p>'As for those who persist in sin, rebuke them in the presence of all, so that the rest may stand in fear' — public discipline for persisting elders serves the Christological community's health. The fear produced is the fear of God that is the beginning of wisdom (Prov 1:7) — a fear that is simultaneously the recognition of standing before Christ's judgment (2 Cor 5:10: we must all appear before the judgment seat of Christ). Discipline in the community is a present form of the eschatological judgment that Christ will exercise.</p>",
    "21": "<p>'In the presence of God and of Christ Jesus and of the elect angels I charge you to keep these rules without prejudging, doing nothing from partiality' — the solemn charge before the divine court places Timothy's administration of elder-discipline in an eschatological frame. Christ Jesus is named as witness alongside God the Father: the judgment of the community's elders by Timothy is overseen by the one who will judge the living and the dead (2 Tim 4:1: in the presence of God and of Christ Jesus, who is to judge the living and the dead). Timothy's partiality-free administration reflects the impartiality of the final judge.</p>",
    "22": "<p>'Do not be hasty in the laying on of hands, nor take part in the sins of others; keep yourself pure' — the laying on of hands that installs leaders is a Christological act: leaders are installed to serve Christ's community in Christ's name. Hasty installation of unworthy leaders implicates Timothy in what those leaders subsequently do, because he has vouched for them before Christ. The purity Timothy is to maintain is not merely personal moral integrity but Christological fidelity: he is to maintain standards worthy of the Christ in whose service the leaders are being installed.</p>",
    "23": "<p>'No longer drink only water, but use a little wine for the sake of your stomach and your frequent ailments' — the personal medical advice grounds Timothy's bodily health in the Christological framework of embodied service. Christ's incarnation affirms the body's significance; caring for the body that serves Christ is a proper expression of the embodied discipleship that flows from the Incarnation. The instruction cuts against an ascetic contempt for the body (4:3-5): wine as medicine is precisely the use of a created good (4:4) for the sustaining of bodily service to Christ.</p>",
    "24": "<p>'The sins of some people are conspicuous, going before them to judgment, but the sins of others appear later' — the judgment before which sins arrive is ultimately Christ's final judgment (2 Tim 4:1; 2 Cor 5:10). The observation has pastoral relevance: the administrator of community discipline (Timothy) operates with limited perception; Christ the final judge operates with perfect perception. Timothy's human scrutiny is partial; Christ's eschatological judgment will be complete. The instruction counsels humility about present assessment while maintaining confidence in eschatological justice.</p>",
    "25": "<p>'So also good works are conspicuous, and even those that are not cannot remain hidden' — the eschatological unveiling of hidden good works mirrors the promise that Christ will bring to light the things hidden in darkness and disclose the purposes of the heart (1 Cor 4:5: he will bring to light the things hidden in darkness and disclose the purposes of the heart). The final judgment's full revelation is not only of sin but of righteousness; the good works done in secret will be acknowledged before the whole court of heaven by the righteous judge.</p>"
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-christ', '1timothy')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', '1timothy', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / '1timothy.json'))
    all_ok = True
    for ch in ['1', '2', '3', '4', '5']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ch, {}))} verses)')
    if all_ok:
        print('All verses present')
